class Mapping:
    def __init__(self, width=2):
        """Create a Mapping instance, which allows, for each element stored, to access to its "width"-1 neighbors
        quickly

        >>> mappingping = Mapping(3)
        >>> mappingping.add([0, 1, 2])
        >>> for x, y, z in mappingping: print(x, y, z)
        0 1 2
        """
        self.dictionaries = [{} for _ in range(width)]

    def get_width(self):
        """Return the "width" of the data structure"""
        return len(self.dictionaries)

    def __len__(self):
        """Return the number of "mapping" stored in the data structure"""
        return len(self.dictionaries[0]) if self.dictionaries else 0

    def check_width(self):
        if not self.get_width():
            raise ValueError(
                "This operation cannot be performed on a Mapping of width 0"
            )

    def check_length(self, mapping):
        if len(mapping) != self.get_width():
            raise ValueError("<mapping> and this Mapping should have the same width")

    def check_contains(self, mapping):
        if Mapping.__contains__(self, mapping):
            raise ValueError(
                "Some components of <mapping> are already contained in this Mapping"
            )

    def add(self, mapping):
        """Stores a "mapping" in the data structure.
        A "mapping" is an enumerable object of size "width" which contains immutable objects
        """
        mapping = mapping[:]
        self.check_length(mapping)
        self.check_contains(mapping)
        for dictionary, x in zip(self.dictionaries, mapping):
            dictionary[x] = mapping

    def __contains__(self, mapping):
        """Return "True" if at least one element of "mapping" is already contained in its corresponding set"""
        self.check_length(mapping)
        for dictionary, x in zip(self.dictionaries, mapping):
            if x in dictionary:
                return True
        return False

    def get(self, key, index):
        """Return the "mapping" of the data structure that has the element key in the set of index <index>"""
        return self.dictionaries[index][key]

    def get_matches(self, mapping) -> list:
        """Find every neighbor of the elements of "mapping"

        :return: a list of mappings of size "width". If the element does not exist in the corresponding set,
        the corresponding position in the returned list is "None"
        """
        self.check_length(mapping)
        matches = [None] * len(mapping)
        for i, (dictionary, x) in enumerate(zip(self.dictionaries, mapping)):
            if x in dictionary:
                matches[i] = dictionary[x]
        return matches

    def remove(self, key, index):
        """Remove the mapping that matches the element key in the set of index "index" """
        mapping = self.get(key, index)
        for dictionary, x in zip(self.dictionaries, mapping):
            del dictionary[x]

    def remove_matches(self, mapping):
        """Remove every mapping that matches with "mapping" """
        self.check_length(mapping)
        for i, (dictionary, x) in enumerate(zip(self.dictionaries, mapping)):
            if x in dictionary:
                self.remove(x, i)

    def __iter__(self):
        if self.get_width():
            for mapping in self.dictionaries[0].values():
                yield mapping

    def __eq__(self, other):
        return self.__dict__ == other.__dict__


class DoubleMapping(Mapping):
    def __init__(self):
        """Create an instance of DoubleMapping, which allows to create a bijection between two sets "X" and "Y" of
        immutable objects
        """
        super(DoubleMapping, self).__init__(width=2)

    def add_couple(self, x, y):
        """Stores "x" in "X", y in "Y" and link them"""
        super(DoubleMapping, self).add((x, y))

    def get_x(self, y):
        """Find the "x" corresponding to the input "y" """
        return self.get(y, 1)[0]

    def get_y(self, x):
        """Find the "y" corresponding to the input "x" """
        return self.get(x, 0)[1]

    def contains_x(self, x):
        """Check if "x" is contained in "X" """
        return [x, None] in self

    def contains_y(self, y):
        """Check if "y" is contained in "Y" """
        return [None, y] in self

    def remove_with_x(self, x):
        """Remove "x" and "y" from the data structure by knowing "x" """
        self.remove(x, 0)

    def remove_with_y(self, y):
        """Remove "x" and "y" from the data structure by knowing "y" """
        self.remove(y, 1)
